const fs = require('fs');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const dates = ctx.key_dates || {}, compliance = ctx.compliance_rules || [], verticals = ctx.verticals || {};
const today = new Date();
const daysUntil = s => Math.ceil((new Date(s) - today) / (1000*60*60*24));
const deadlines = [
  { item: 'MEIA Capstone Submission', date: dates.meia_capstone || '2026-04-14', entity: 'EAF', owner: 'Kevin' },
  { item: 'EAF Annual Report', date: dates.eaf_annual_report || '2026-04-15', entity: 'EAF', owner: 'Kevin' },
  { item: 'OMB M-26-02 Federal Drone Compliance', date: dates.omb_m2602_deadline || '2026-05-20', entity: 'FP', owner: 'Kevin' },
  { item: 'IRS Form 1023 — 501c3 Filing', date: dates.form_1023 || '2026-06-01', entity: 'EAF', owner: 'Kevin' },
  { item: 'MONK LLC Formation', date: '2026-05-01', entity: 'MONK', owner: 'Kevin' },
  { item: 'CAKO Cohort 1 Launch', date: dates.cako_cohort1_launch || '2026-07-01', entity: 'EAF', owner: 'Kevin' },
  { item: 'Fleet 1 Arrival', date: dates.fleet1_arrival || '2026-07-01', entity: 'FP', owner: 'Kevin' },
  { item: 'Microsoft for Nonprofits', date: '2026-04-12', entity: 'EAF', owner: 'Kevin' },
  { item: 'Google for Nonprofits / TechSoup', date: '2026-04-12', entity: 'EAF', owner: 'Kevin' },
  { item: 'Supabase Setup', date: '2026-04-12', entity: 'FP', owner: 'Kevin' },
  { item: 'FAA Part 107 Renewal', date: '2027-12-31', entity: 'FP', owner: 'Kevin' },
];
const overdue = deadlines.filter(d => daysUntil(d.date) < 0);
const critical = deadlines.filter(d => { const n = daysUntil(d.date); return n >= 0 && n <= 7; });
const urgent = deadlines.filter(d => { const n = daysUntil(d.date); return n > 7 && n <= 21; });
const upcoming = deadlines.filter(d => { const n = daysUntil(d.date); return n > 21 && n <= 90; });
let report = `IRIS COMPLIANCE MONITOR v2\nGenerated: ${today.toLocaleString('en-US',{timeZone:'America/New_York'})} EST\nKAI_Context.json: loaded\n\n`;
if (overdue.length) { report += '🔴 OVERDUE:\n'; overdue.forEach(d => { report += `  • ${d.item} — ${Math.abs(daysUntil(d.date))}d overdue [${d.entity}]\n`; }); report += '\n'; }
if (critical.length) { report += '🚨 CRITICAL (7 days):\n'; critical.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}] Owner: ${d.owner}\n`; }); report += '\n'; }
if (urgent.length) { report += '⚠️ URGENT (21 days):\n'; urgent.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}]\n`; }); report += '\n'; }
if (upcoming.length) { report += '📅 UPCOMING (90 days):\n'; upcoming.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}]\n`; }); report += '\n'; }
report += `COMPLIANCE RULES:\n${compliance.map(r=>'• '+r).join('\n')}\n\n`;
report += `REGULATORY WATCH:\n• FAA Part 108 BVLOS final rule INCOMING — flagged for Atlas SBIR\n• FAA-2022-1258 BVLOS rulemaking active\n• OMB M-26-02 deadline: ${dates.omb_m2602_deadline || '2026-05-20'}\n`;
const outputPath = `/data/Aidan_Outputs/Iris/Iris_Report_${today.toISOString().replace(/[:.]/g,'-')}.txt`;
fs.mkdirSync('/data/Aidan_Outputs/Iris', { recursive: true });
fs.writeFileSync(outputPath, report, 'utf8');
let whatsappMsg = 'Bot reply: IRIS COMPLIANCE REPORT\n\n';
if (overdue.length) { whatsappMsg += `🔴 OVERDUE (${overdue.length}):\n`; overdue.forEach(d => { whatsappMsg += `• ${d.item}\n`; }); whatsappMsg += '\n'; }
if (critical.length) { whatsappMsg += `🚨 CRITICAL (${critical.length}):\n`; critical.forEach(d => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; }); whatsappMsg += '\n'; }
if (urgent.length) { whatsappMsg += `⚠️ URGENT (${urgent.length}):\n`; urgent.forEach(d => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; }); }
whatsappMsg += '\nPart 108 BVLOS: INCOMING — flagged for Atlas.';
const summary = `IRIS COMPLETE\nCritical: ${critical.length} | Urgent: ${urgent.length} | Overdue: ${overdue.length}\nSaved: /data/Aidan_Outputs/Iris/`;
return [{ json: { report, whatsappMsg, summary, criticalCount: critical.length, urgentCount: urgent.length, overdueCount: overdue.length, savedTo: outputPath } }];

